using UnityEngine;
public class GlazeSystem : MonoBehaviour
{
    [SerializeField] private OrderManager orderManager;
    public string TargetGlazeName { get; private set; }
    public float TargetKaolin { get; private set; }
    public float TargetAsh { get; private set; }
    public float TargetCopper { get; private set; }
    public float TargetIron { get; private set; }
    public float TargetCobalt { get; private set; }
    public bool HasTarget { get; private set; }
    public float GlazeMatch { get; private set; }
    private void Awake()
    {
        LoadTargetFromCurrentOrder();
    }
    public bool LoadTargetFromCurrentOrder()
    {
        HasTarget = false;

        if (orderManager == null)
        {
            return false;
        }

        OrderData currentOrder = orderManager.GetCurrentOrder();
        if (currentOrder == null || currentOrder.glazeRecipe == null)
        {
            return false;
        }

        GlazeRecipeData recipe = currentOrder.glazeRecipe;
        TargetGlazeName = recipe.glazeName;
        TargetKaolin = recipe.kaolin;
        TargetAsh = recipe.ash;
        TargetCopper = recipe.copper;
        TargetIron = recipe.iron;
        TargetCobalt = recipe.cobalt;
        HasTarget = true;
        return true;
    }
    public float CalculateMaterialError(float playerValue, float targetValue)
    {
        return Mathf.Abs(Mathf.Clamp01(playerValue) - Mathf.Clamp01(targetValue));
    }
    public float CalculateKaolinError(float playerValue)
    {
        return CalculateMaterialError(playerValue, TargetKaolin);
    }
